mapper.select:
SELECT COALESCE(SUM(call_count), 0)
FROM usage_hourly
WHERE app_id = #{appId}
  AND bucket_hour >= #{from}
  AND bucket_hour < #{to}

SELECT COALESCE(SUM(call_count), 0)
FROM usage_hourly
WHERE app_id = #{appId}
  AND bucket_hour >= #{from}
  AND bucket_hour < #{to}
  AND status_bucket IN ('4xx', '5xx')

SELECT COALESCE(SUM(latency_sum_ms), 0)
FROM usage_hourly
WHERE app_id = #{appId}
  AND bucket_hour >= #{from}
  AND bucket_hour < #{to}

SELECT
    DATE_FORMAT(bucket_hour, '%Y-%m-%d') AS bucket,
    COALESCE(SUM(call_count), 0)         AS callCount,
    COALESCE(SUM(CASE WHEN status_bucket IN ('4xx','5xx') THEN call_count ELSE 0 END), 0) AS errCount
FROM usage_hourly
WHERE app_id = #{appId}
  AND bucket_hour >= #{from}
  AND bucket_hour < #{to}
GROUP BY DATE_FORMAT(bucket_hour, '%Y-%m-%d')
ORDER BY bucket ASC

SELECT
    DATE_FORMAT(bucket_hour, '%Y-%m-%d %H:00') AS bucket,
    COALESCE(SUM(call_count), 0)               AS callCount,
    COALESCE(SUM(CASE WHEN status_bucket IN ('4xx','5xx') THEN call_count ELSE 0 END), 0) AS errCount
FROM usage_hourly
WHERE app_id = #{appId}
  AND bucket_hour >= #{from}
  AND bucket_hour < #{to}
GROUP BY DATE_FORMAT(bucket_hour, '%Y-%m-%d %H:00')
ORDER BY bucket ASC

SELECT
    endpoint_group                     AS endpointGroup,
    SUM(call_count)                    AS callCount,
    SUM(CASE WHEN status_bucket IN ('4xx','5xx') THEN call_count ELSE 0 END) AS errCount
FROM usage_hourly
WHERE app_id = #{appId}
  AND bucket_hour >= #{from}
  AND bucket_hour < #{to}
GROUP BY endpoint_group
ORDER BY callCount DESC
LIMIT #{limit}
